        Map<String, Object> claimsHelperMethod(String vpToken) throws Exception{
            id.walt.sdjwt.SDJwt unverifiedSDJwt = openID4VPResponseService.unverifiedSDJwt(vpToken);
            X509Certificate cert = openID4VPResponseService.certificate(unverifiedSDJwt);
            JWSVerifier jwsVerifier = openID4VPResponseService.jwsVerifier(cert);
            JWSAlgorithm jwsAlgorithm = openID4VPResponseService.algorithm(cert);
            SimpleJWTCryptoProvider cryptoProvider = new SimpleJWTCryptoProvider(jwsAlgorithm, null, jwsVerifier);
            VerificationResult<id.walt.sdjwt.SDJwt> result = openID4VPResponseService.verificationResult(cryptoProvider, unverifiedSDJwt);
            Map<String, Object> claims = openID4VPResponseService.retrieveClaimsFromSDJwtCredential(result);
            return claims;
        }

        VerificationResult<id.walt.sdjwt.SDJwt> verificationResultHelperMethod(String vpToken) throws Exception {
            id.walt.sdjwt.SDJwt unverifiedSDJwt = openID4VPResponseService.unverifiedSDJwt(vpToken);
            X509Certificate cert = openID4VPResponseService.certificate(unverifiedSDJwt);
            JWSVerifier jwsVerifier = openID4VPResponseService.jwsVerifier(cert);
            JWSAlgorithm jwsAlgorithm = openID4VPResponseService.algorithm(cert);
            SimpleJWTCryptoProvider cryptoProvider = new SimpleJWTCryptoProvider(jwsAlgorithm, null, jwsVerifier);
            return openID4VPResponseService.verificationResult(cryptoProvider, unverifiedSDJwt);
        }

        StatusSdJwt statusHelperMethod(VerificationResult<id.walt.sdjwt.SDJwt> verificationResult) throws Exception {
            return openID4VPResponseService.extractStatuslistUriAndIdx(verificationResult);
        }

